var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"흐음…","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"이 정도면 충분히 모았나?","JPN":"もう十分か？","ENG":"Will this be enough?","TWN":"這樣就足夠了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"또 혼자서 돌아다니던 거니?","JPN":"また一人で歩き回っていたのかしら。","ENG":"Have you been wandering alone again?","TWN":"…你又一個人到處亂跑嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"이제 막 돌아가려던 참입니다.","JPN":"今帰ろうとしていたところです。","ENG":"I was just making my way back.","TWN":"我正準備回去了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"유행병 치료제에 쓸 약초가 부족하다고 들어서요. 다들 손발이 바쁜 시기잖습니까?","JPN":"流行り病の治療剤に使う薬草が足りないと聞きましたので。みんな忙しい時期ではないですか。","ENG":"I heard there is a shortage of herbs used to treat the epidemic disease, and everyone is already so busy.","TWN":"聽說治療流行病的藥草不夠，大家都很忙吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아무리 그래도 아발론의 왕이 산중에서 풀을 캐고 있다니.","JPN":"いくらなんでもアバロンの王が山の中で草を集めているなんて。","ENG":"Even if so, the king of Avalon is plucking herbs in the mountains?","TWN":"再怎麼說，阿瓦隆的王在山中一個人採摘草藥也太奇怪了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"신하들이 알게 되면 또 까무러치겠네.","JPN":"臣下がそれを知るとまた仰天するわ。","ENG":"Your subjects will be horrified if they found out.","TWN":"如果臣子們知道了，又會嚇死吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"왕이 백성을 만날 때에도 군대를 대동하라는 사람들이니까요.","JPN":"王が民に会う時にも軍隊を連れていけという人たちですから。","ENG":"As they summon the entire army when the king goes to meet his people.","TWN":"他們可是連王接見百姓都要帶上一整支軍隊的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"아마 제 베갯머리에서 거미가 나와도, 성안의 온 경비를 소집할 겁니다.","JPN":"きっと私の枕からクモが出ても、城の中の警備を全員呼び集めるでしょう。","ENG":"They would even call upon all the guards within the castle if so much as a spider came out from my pillowcase.","TWN":"要是我的枕頭裡爬進了一隻蜘蛛，甚至也會把所有守衛都叫進來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그런 과보호가 마냥 나쁜 건 아니야.","JPN":"でも過保護だからって悪いことばかりじゃないわ。","ENG":"Being overprotective is not always bad.","TWN":"這種過度保護也不全是壞事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"사람의 앞길은 요정도 모르는 거잖니?","JPN":"人の未来なんて妖精にもわからないものよ。","ENG":"Not even a fairy knows what the future holds, no?","TWN":"就連精靈也不知道接下來發生的每件事吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하하, 미래를 보는 요정께서 그런 말씀을 하다니. 재밌네요.","JPN":"はは、未来を見る妖精さんにそう言われるとは。面白いですね。","ENG":"Haha, funny that the fairy with foresight would say such a thing.","TWN":"哈哈，能預見未來的精靈竟然這麼說。真有趣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"농담이 아니야. 우리의 예언 중엔 아주 사소한 것이 계기가 되는 비극도 많으니까.","JPN":"冗談じゃないわ。アタシたちの予言の中には、とても些細なことがきっかけで起きる悲劇もあるんだから。","ENG":"I am not joking. Our prophecies tend to cause tragedies by even the smallest of things.","TWN":"這不是玩笑，我們的預言中有很多因小事而引發的悲劇。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하지만 그런 작은 사소한 계기가 비극을 막아낸 역사도 적지 않죠.","JPN":"ですが、そのような些細なきっかけが悲劇を防いだ歴史も少なくありません。","ENG":"But history has told of times when those insignificant moments also stopped tragedy.","TWN":"但也有不少因小小的契機而阻止了悲劇的歷史。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"한낱 인간이 수 천 년의 역사를 아우르며 칭송받는 영웅의 이야기. 멋지지 않나요?","JPN":"一介の人間が数千年にわたり称えられる英雄になる話。素晴らしいとは思いませんか？","ENG":"A hero's tale of a mere human being praised for a thousand years. Isn't that wonderful?","TWN":"一個普通人能夠跨越千年的歷史，被後世稱頌為英雄。不是很棒嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"왕은 영웅이 되어선 안 돼.","JPN":"王は英雄になってはいけないの。","ENG":"A king must not become a hero.","TWN":"王不應該成為英雄。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 호기로움과 정의로움이 결국 약점이 되어서 단명하고 말거든.","JPN":"その豪気と正義感が、結局は弱点になって早死にするのよ。","ENG":"Curiosity and righteousness will eventually become his weakness, leading to death.","TWN":"那種勇敢和正義最終會成為弱點，成為短命的理由。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"그건 요정으로서 하는 예언인가요?","JPN":"それは妖精としての予言でしょうか？","ENG":"Is that a prophecy from you as a fairy?","TWN":"這是作為精靈的預言嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"왕의 조언자로서 하는 충고야.","JPN":"王の助言者としての忠告よ。","ENG":"It is advice from your advisor.","TWN":"這是作為王的顧問的忠告。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"그렇다면 새겨듣도록 하죠.","JPN":"ならば肝に銘じましょう。","ENG":"Then I will keep it to heart.","TWN":"那麼，我會銘記在心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"현명한 왕이 되려면 솔직한 스승이 필요한 법이니까요.","JPN":"賢明な王になるためには、正直者の師匠が必要ですから。","ENG":"A wise king requires an honest teacher.","TWN":"一個明智的王身邊，總是會有一個坦誠的導師。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그냥 현명한 왕이 되게 해달라고 소원을 빌어보는 건 어때?","JPN":"いっそ賢明な王になれますようにと願うのはどうかしら。","ENG":"How about just wishing to become a wise king?","TWN":"要想成為明智的君王，為什麼你不許願這麼做呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"아발론의 왕은 평생에 한 번 요정에게 소원을 빌 수 있다고 하죠.","JPN":"アバロンの王は一生に一度だけ妖精に願いを叶えてもらえるそうですね。","ENG":"The king of Avalon is said to be given one wish during his lifetime.","TWN":"據說阿瓦隆的王一生只能向精靈許一個願望。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하지만 자신만을 위해 소원을 비는 것은 금기입니다.","JPN":"しかし、自分のために願うのは禁忌です。","ENG":"However, wishing something for myself is forbidden.","TWN":"但為自己許願是禁忌。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래? 지금까지의 왕들은 나를 위하는 것이 곧 대국적인 일이라면서 잘만 포장하던데.","JPN":"そう？　今までの王は、自分のために願うことが世のためになるって、もっともらしく言っていたけれど。","ENG":"Is that so? Those before you have always seemed to find a way to present it to me as if it were something of national importance.","TWN":"是嗎？到目前為止的王都假借著國家的名義，為自己許下了願望，並且他們包裝得很好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"어쩌면 제가 틀렸을지도 모르죠. 신념이란 명목으로 오기를 부리는 걸 수도 있고요.","JPN":"もしかしたら私が間違っているのかもしれません。信念という名目で、意地を張っているだけなのかも。","ENG":"Maybe I am in the wrong. Or I may be acting arrogantly in the name of faith.","TWN":"也許我錯了，也許這是我以信念為名的固執。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하지만 꼭 소원을 빌어야 한다면… 일평생을 바쳐도 이루지 못할 일에 쓰고 싶습니다.","JPN":"ですが、願いを叶えてもらうなら……人生を捧げても叶えられないようなことを願いたい。","ENG":"But if I were to make a wish... I want to use it on something I cannot achieve in my lifetime.","TWN":"但如果一定要許願的話…我願意用它去實現一個我窮盡一生都不可能實現的願望。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"인류사는 영원하지만, 한 인간의 삶이란 건 그저 찰나일 뿐이니까요.","JPN":"人類の歴史は永遠ですが、一介の人間の人生は刹那ですから。","ENG":"Human history is eternal, but the life of one is but a moment.","TWN":"人類歷史是永恆的，但個人的生命只是瞬間。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"걱정 마. 당신은 이미 현명한 왕이야.","JPN":"心配しないで。アナタはすでに賢明な王よ。","ENG":"Worry not. For you are already as wise as they come.","TWN":"別擔心，你已經是個明智的王了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아주 제멋대로라서 문제긴 하지만.","JPN":"自分勝手なのが問題だけど。","ENG":"The only issue is of your recklessness.","TWN":"雖然有點任性的小問題。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하하하, 솔직하시네요.","JPN":"ははは、正直ですね。","ENG":"Hahaha! Honesty at its finest.","TWN":"哈哈哈，你真誠坦率。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"전 그런 당신이 좋습니다.","JPN":"私はそんなあなたが好きです。","ENG":"That is what I like about you.","TWN":"我喜歡這樣的你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"え……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"그러니 부디, 제 이름을 불러주시겠어요?","JPN":"だからどうか、私のことは名前で呼んでくれませんか？","ENG":"So please, could you call me by my name?","TWN":"所以，請叫我的名字好嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"요정은 인간의 이름을 함부로 부르지 않아.","JPN":"妖精はむやみに人間の名前を呼んだりしないわ。","ENG":"A fairy does not carelessly speak the names of humans.","TWN":"精靈不會隨便叫人的名字。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"유대가 생겨버리고 말거든.","JPN":"絆ができちゃうの。","ENG":"For a bond will form.","TWN":"這會建立起羈絆。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"두려우신가요? 영생의 존재가 단명하는 존재에게 마음을 주는 것이?","JPN":"怖いのですか？　永生な存在が、短命する存在に心を寄せるのが。","ENG":"Are you afraid? Giving your eternal heart to a mere fleeting soul?","TWN":"你在害怕嗎？因為永生的存在對短命的存在動了心？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그렇게 겁쟁이냐고 찔러대면… 나 참지 못하는데.","JPN":"そんなふうに言われたら……アタシ、我慢できなくなるじゃない。","ENG":"If you keep calling me a coward... I will have no choice but to oblige.","TWN":"如果你一直這樣嘲笑我…我可忍不住了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"나도 요정 중에선 제법 호기로운 편이거든.","JPN":"アタシも妖精の中では結構豪気のある方なんだから。","ENG":"For I lean toward curiosity amongst the other fairies.","TWN":"在精靈中，我也算是相當勇敢的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"역시, 우린 닮은 점이 많군요.","JPN":"やはり、私たちは似ている点が多いですね。","ENG":"I knew it. You and I have a lot in common.","TWN":"果然，我們有很多相似之處。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"그렇지 않나요? 멀린?","JPN":"そうではありませんか？　マーリン。","ENG":"Don't you think so too, Merlin?","TWN":"不是嗎？梅林？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"훗…","JPN":"ふふっ……","ENG":"Hmph...","TWN":"呵…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"그때, 내가 네 이름을 부르지 않았다면…","JPN":"あの時、アタシがアナタの名前を呼ばなかったら……","ENG":"If only I did not say your name back then...","TWN":"那時，如果我沒有呼喚你的名字…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 널 잊을 수 있었을까?","JPN":"アタシはアナタのことを忘れられたのかしら？","ENG":"would I have been able to forget about you?","TWN":"我能夠忘記你嗎…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GENERAL_ROOT_NPC_NULL","text":{"KOREA":"국왕 폐하를 보호해라! 어서 반역자를 찾아!","JPN":"国王陛下を保護しろ！　早く反逆者を探せ！","ENG":"Protect His Majesty the King! Find the traitor!","TWN":"保護國王陛下！快找出叛徒！"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_03"},{"id":"L18_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"미안해요… 멀린…","JPN":"ごめんなさい……マーリン……","ENG":"I'm sorry... Merlin...","TWN":"抱歉…梅林…"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"당신의 조언대로 모든 사람을 의심했다면… 이렇게 한심하게 누워있진 않았겠죠.","JPN":"あなたの助言どおり、すべての人間を疑っていたなら……こうして惨めに討たれることもなかった。","ENG":"If I had only been more suspicious of everyone as you advised me... then I wouldn't be lying so helplessly here.","TWN":"如果按照你的建議懷疑所有人…我就不會這麼可憐地躺在這裡了吧。"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"말하지 않아도 돼! 반성 같은 건 나중에 해도 늦지 않아!","JPN":"話さなくていいわ！　反省なんて、後からしても遅くないの！","ENG":"Speak no more! It will not be too late to reflect on your actions later!","TWN":"不用說了！要反省之後再反省吧！"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"망할… 왜 치료가 안되는 거야…?!","JPN":"もうっ……どうして治療できないの……！？","ENG":"Dammit...! Why is the treatment not working...?!","TWN":"該死…為什麼治不好…？！"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 놈이 대체 뭘 쓴 거지…? 내 권능조차 듣질 않는 독이라고?","JPN":"あいつ、いったい何を使ったのよ……？　アタシの権能が効かない毒だなんて。","ENG":"What did he do to you...? A poison that will not respond to my power?","TWN":"那傢伙到底用了什麼…？連我的權能都無效的毒藥？"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"쿨럭…","JPN":"ゲホッ……","ENG":"*Cough*","TWN":"咳咳…"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"아무래도… 전 여기까진 것 같네요.","JPN":"どうやら……私はここまでのようですね。","ENG":"I think... my time has come to an end.","TWN":"看來…我也只能到這裡了。"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"제 어리석은 실수 때문에… 당신에게 이런 꼴을 보여서 미안해요.","JPN":"私の愚かな失敗のせいで……あなたにこんな姿を見せてしまってすみません。","ENG":"I apologize for my appearance... all because of my foolish mistake...","TWN":"因為我的愚蠢失誤…讓你看到我這副模樣，真是抱歉。"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"안돼…! 제발…!","JPN":"ダメ……！　お願い……！","ENG":"No...! Please...!","TWN":"不要…！拜託了…！"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이런 식으로 널 잃을 순 없어!","JPN":"こんな形でアナタを失うわけにはいかないわ！","ENG":"I cannot lose you like this!","TWN":"我不能就這樣失去你！"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"당신의 손길이… 오늘따라 참 따뜻하군요.","JPN":"あなたの手……今日は一段と温かい。","ENG":"Your hands... they seem warmer than usual today.","TWN":"你的手…今天特別溫暖。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"듣고 있다면… 부탁이 있어요, 멀린.","JPN":"聞いているなら……頼みたいことがあります、マーリン。","ENG":"If you are listening... I have a request, Merlin.","TWN":"如果你在聽…我有個請求，梅林。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래…! 말해! 소원이라면 아직 빌 수 있어!","JPN":"ええ……！　話しなさい！　願いを叶えることならまだできるわ！","ENG":"Yes...! Tell me! You can still make your wish!","TWN":"好…！說吧！如果是願望的話，那你許吧！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"널 이렇게 만든 놈들에게 복수해달라고 해! 내가 그것들을 불태워서라도 갚아줄 테니까!","JPN":"アナタをこうしたやつらに復讐してほしいって言いなさい！　アタシがそいつらを燃やし尽くしてあげる！","ENG":"Tell me to exact revenge on the ones who made you like this! I shall hail hellfire down on them!","TWN":"許願我向那些把你變成這樣的傢伙復仇！我會將他們燒成灰燼來為你報仇！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"제가 죽더라도… 인간들을 미워하지 말아줘요.","JPN":"私が死んでも……人間のことを嫌わないでください。","ENG":"Even if I die... please do not harbor hatred toward us humans.","TWN":"即便我死了…也不要憎恨人類。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"え……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그게 무슨 소리야! 인간이라면 널 이렇게 만든 녀석에게 복수를 원하는 게 당연하잖아!","JPN":"何よ、それ！　人間なら当然、復讐を願うはずでしょう！","ENG":"What is this nonsense?! If you are human, it is natural to seek vengeance to the one who made you like this!","TWN":"你在說什麼啊！作為人類，想要向讓你變成這樣的傢伙復仇是理所當然的吧！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"독이 너무 깊이 파고 들었습니다.","JPN":"毒があまりにも深くまで達しています。","ENG":"The poison has spread too deeply.","TWN":"毒已經深入了。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"한참 전부터… 이미 시력과 청력이 온전치 못한 상태이셨을 겁니다.","JPN":"随分前から……視力と聴力は失っていたでしょう。","ENG":"His hearing and vision... may have been lost a long time ago.","TWN":"王的視力和聽力…已經不太好了。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"인간의 삶은… 길어야 고작 백 년을 넘기지 못합니다.","JPN":"人間の人生は……長くても百年は越えません。","ENG":"The lifespan of a human... is shy of just a hundred years.","TWN":"人類的生命…就算再長也不過百年。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"어리석은 죄인도… 용감한 영웅도… 결국 세월이 흘러 역사 속으로 사라지고 맙니다.","JPN":"愚かな罪人も……勇敢な英雄も……結局は月日が経ち、歴史の中へと消えてしまいます。","ENG":"Foolish sinners... and courageous heroes... all fade away into history with time.","TWN":"愚蠢的罪人…勇敢的英雄…最終都會隨著時間的流逝消失在歷史中。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하지만, 인류의 역사와 당신은… 내 이름을 영원히 기억한 채 살아가겠죠.","JPN":"ですが、人類の歴史とあなたは……私の名を永遠に記憶するでしょう。","ENG":"However, humanity's history and you... will forever remember my name and live on.","TWN":"但是，人類的歷史，還有你…會永遠記住我的名字。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"제 이름이 당신에게… 영원한 증오가 아닌 희망으로 남는 것…","JPN":"私の名前があなたの中で……憎悪ではなく、希望として残ること……","ENG":"To leave my name... as a sign of hope and not hatred...","TWN":"希望我的名字…能在你心中留下希望，而不是永恆的仇恨…"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"그것이 내 마지막…","JPN":"それが私の最後の……","ENG":"That is my last...","TWN":"這是我最後的…"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"부탁입니다.","JPN":"頼みです。","ENG":"Request.","TWN":"請求。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"부탁… 이라고…?","JPN":"頼み……？","ENG":"Request...?","TWN":"請求…嗎…？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GENERAL_ROOT_NPC_NULL","text":{"KOREA":"국왕 폐하…!!","JPN":"国王陛下……！！","ENG":"Your Majesty...!!","TWN":"國王陛下…！！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GENERAL_ROOT_NPC_NULL","text":{"KOREA":"뭣들 하나! 당장 나라에 모든 병사를 풀어 반역자를 잡아들여라!","JPN":"何をしている！　今すぐにすべての兵士を送り、反逆者を捕まえろ！","ENG":"What are you all doing?! Order all the nation's soldier to catch the traitor!","TWN":"你們在幹什麼！立即派出所有士兵，抓住叛徒！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"GENERAL_ROOT_NPC_NULL","text":{"KOREA":"그 일가와 공모자들을 하나도 남김 없이 재판에 세울 것이다!","JPN":"あの一家と共犯を、一人残さず裁判にかける！","ENG":"His family and conspirators will all be put on trial!","TWN":"我要將他們的家族和同謀，一個不留地送上審判台！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"요정에게 있어, 아발론의 왕이 바라는 소원은 절대적인 명령과 같아.","JPN":"妖精にとって、アバロンの王の願いは絶対的な命令のようなもの。","ENG":"For the fairy, the wish from the king of Avalon is like an absolute order.","TWN":"對於精靈來說，阿瓦隆之王的願望就像絕對的命令。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 넌 왜… 나에게 부탁을 한 걸까?","JPN":"でも、アナタはどうして……アタシに頼みごとをしたのかしら。","ENG":"But why... did you make a request for me?","TWN":"但你為什麼…向我提出請求呢？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"내가 정말로 널 죽인 인간들을 사랑하길 바랐다면, 어째서 소원이 아닌 부탁을 남긴 걸까?","JPN":"アタシが本当にアナタを殺した人間たちを愛すことを望んでいたのなら、どうして願いではなく頼みを言ったの？","ENG":"If you truly wish for me to love the human who killed you, why is it a request and not your wish?","TWN":"如果你真的希望我愛上那些殺了你的人，為什麼留下的不是願望而是請求呢…？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇구나.","JPN":"そうか。","ENG":"I see.","TWN":"原來是這樣。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"실은 너도… 복수를 원했던 거야.","JPN":"本当はアナタも……復讐してほしかったのね。","ENG":"In truth... you also wanted to get revenge.","TWN":"其實你也…渴望復仇吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"끝내 선량한 군자로 남기를 택한 널 대신해… 내가 손을 더럽히면 되는 거야.","JPN":"最後まで善良な王として残ることを選んだアナタの代わりに……アタシが手を汚してしまえばいいわ。","ENG":"I was to get blood on my hands... so you could remain a benevolent ruler.","TWN":"你選擇成為自始至終善良的君主…所以由我來弄髒雙手。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇지?","JPN":"そうでしょう？","ENG":"Right?","TWN":"我說的對吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"판결을 내린다.","JPN":"判決を下す。","ENG":"I hereby sentence thee.","TWN":"我將作出判決。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"죄인은 왕의 형제라는 신분을 이용해 왕위를 찬탈하고자 반역이란 만행을 저질렀다.","JPN":"罪人は王の兄弟であるという身分を利用し、王位を簒奪しようと反逆という蛮行を犯した。","ENG":"The sinner has used his status as the king's brother to commit treason and usurp the throne.","TWN":"罪人利用王弟的身份，企圖篡奪王位，犯下了叛逆的罪行。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"감히 아발론의 왕을 시해한 죄는 고작 한 번의 죽음으로 끝나지 않을 테니…","JPN":"アバロンの王を弑した罪は、一度だけの死では償いきれない……","ENG":"The sin for assassinating the king of Avalon will not end with a single death.","TWN":"膽敢弑殺阿瓦隆之王的罪行，不會僅僅以一次死亡結束…"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 영혼에 반역자의 낙인을 새겨, 영원히 그 죄업의 무게를 짊어지게 될 것이다.","JPN":"その魂に反逆者の烙印を刻み、永遠にその業を背負いなさい。","ENG":"Your soul will be branded with the mark of the traitor, and you will bear the weight of your sin forever.","TWN":"我將在你等的靈魂上烙下叛徒的印記，永遠背負罪孽的重擔。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":" <color=#ffd34c>반역자에게 죽은 아발론의 옛왕이 훗날 동토에서 다시 태어나 그루터기를 이끌리라.</color>","JPN":" <color=#ffd34c>反逆者に殺されたアバロンの昔の王が近い将来、凍土で生まれ変わり、切り株を導くであろう。</color>","ENG":"<color=#ffd34c>The old king of Avalon, slain by the traitor, will be reborn in the gelid lands and lead the Stump.</color>","TWN":"<color=#ffd34c>遭叛徒殺害的阿瓦隆國王，將來會在凍土重生並帶領木墩。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_ROOT_DRUID_IN_STORY_22"},{"id":"L25_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"이것 보세요. 눈 사이에 핀 꽃이네요.","JPN":"見てください。雪の中に花が咲いています。","ENG":"Look. A flower has bloomed amidst the snow.","TWN":"你看這個，是開在雪中的花。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"멀린이 찾던 약초, 맞죠?","JPN":"マーリンが探していた薬草なのでしょう？","ENG":"This is the herb you were looking for, right, Merlin?","TWN":"這是梅林在找的藥草，對吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그러네. 간신히 찾았어.","JPN":"そうね。やっと見つけたわ。","ENG":"Yes. We have finally found it.","TWN":"是啊，終於找到了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"이걸로, 그 아이가 다시 건강을 되찾으면 좋겠군요.","JPN":"これで、あの子がまた健康になるといいですね。","ENG":"With this, I hope that the child will be back in good health.","TWN":"希望這能讓那個孩子恢復健康。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"당신도 그렇게 생각하나요?","JPN":"あなたもそう思うでしょう？","ENG":"Do you hope that as well?","TWN":"你也是這麼想的吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"어?","JPN":"え？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨…! 돌아오셨군요!","JPN":"マーリンさん……！　戻ってきたんですね！","ENG":"Merlin...! You're back!","TWN":"梅林祭司長…！你回來了！"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"미안. 많이 안 늦었지?","JPN":"ごめんなさい。まだ間に合うわよね？","ENG":"Sorry. Am I not too late?","TWN":"抱歉，我沒來晚吧？"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아…","JPN":"あ……","ENG":"Ah...","TWN":"嗯…"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 아직 의식이 돌아오지 않고 있어요.","JPN":"まだモルガナの意識は戻っていません。","ENG":"Morgana still hasn't regained consciousness.","TWN":"莫甘娜還沒有恢復意識。"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"치유사분들 말로는 이상할 정도로 상처 회복이 더뎌서, 이대로라면…","JPN":"治癒師のみなさんの話では不思議なほど怪我の回復が遅くて、ここままだと……","ENG":"The healer said her recovery is strangely slow. At this rate...","TWN":"醫生說她的傷口恢復得異常緩慢，如果繼續這樣下去…"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"마왕의 권능은 씻어낼 수 없는 역병과 같아.","JPN":"魔王の権能は洗い流すことのできない疫病も同然だわ。","ENG":"The Demon Lord's power is like the plague. It cannot be cleansed.","TWN":"魔王的權能如同無法洗淨的瘟疫。"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 뒤틀린 힘이 성자의 힘을 역류시켜 신체를 망가트리고 있는 거지.","JPN":"そのねじれた力が聖者の力を逆流させて、身体を壊しているのよ。","ENG":"The twisted power is regurgitating the Helgon's power and destroying her body.","TWN":"那扭曲的力量逆流了聖者的力量，正在破壞她的身體。"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼 모르가나는… 어떻게 되는 거죠?","JPN":"じゃあ、モルガナは……どうなるんですか？","ENG":"Then... what will happen to Morgana?","TWN":"那莫甘娜…會怎麼樣？"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"상태가 계속 악화되다가, 결국은 죽게 될 거야.","JPN":"状態が悪化し続けて、最後は死んでしまう。","ENG":"Her condition will worsen, and ultimately die.","TWN":"狀態持續惡化，最終會死的。"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럴 수가…","JPN":"そんな……","ENG":"But that can't be...","TWN":"怎麼會…"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아녜요! 모르가나가 이런 식으로 죽을 리 없어요!","JPN":"いいえ！　モルガナがこんなことで死ぬはずがありません！","ENG":"NO! Morgana will never die like this!","TWN":"不，不可能！莫甘娜不會這樣死的！"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨라면…! 뭔가 방법이 있는 거죠? 그렇죠?","JPN":"マーリンさんなら……！　何か方法があるんですよね？　そうですよね？","ENG":"But you, Merlin...! You have a way to cure her, right?","TWN":"如果是梅林祭司長的話…！一定有辦法的，對吧？"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이 약초를 달여서 먹이도록 해.","JPN":"この薬草を煎じて飲ませなさい。","ENG":"Boil this herb and make her drink it.","TWN":"把這個草藥煎好給她服下。"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그럼 곧 증상이 호전될 테니까.","JPN":"きっとすぐ症状がよくなるはずよ。","ENG":"Then, her symptoms will soon subside.","TWN":"這樣很快症狀就會好轉的。"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"정말인가요? 역시…!","JPN":"本当ですか？　さすが……！","ENG":"Really? I knew it...!","TWN":"真的嗎？果然…！"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만 그전에 너도 알아 둬야 할 게 있어.","JPN":"でも、その前にアナタが知っておくべきことがあるわ。","ENG":"However, there is something you should know beforehand.","TWN":"不過在那之前，你也要知道一件事。"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이 약을 먹이면, 이 아이의 삶은 이전과는 완전히 달라질 거야.","JPN":"この薬を飲むと、この子の人生は前とは完全に変わってしまう。","ENG":"If she consumes this herb, her life will be completely different from before.","TWN":"服下這劑藥後，這孩子的生活將會完全不同。"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…?","JPN":"え……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"CAMP","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"말씀처럼 상처가 아물고 있네요.","JPN":"マーリンさんの言ったとおり、傷が治ってますね。","ENG":"Her wound is healing like you said it would.","TWN":"傷口開始癒合了，和梅林說的一樣。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"휴우, 다행이다.","JPN":"ふう、よかった。","ENG":"Phew, I'm so relieved.","TWN":"呼，太好了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그 잠깐 사이에 약을 구해오시다니. 멀린 씨가 아니었으면 정말 큰일날 뻔했어요.","JPN":"こんなにもすぐに薬を探してくるなんて。マーリンさんがいなければ大変なことになるところでした。","ENG":"If you hadn't found the medicine so quickly, Morgana would've been in real trouble, Merlin.","TWN":"在短短的時間內就找到了藥。如果不是梅林祭司長，真的會出大事。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"애써 아무렇지 않은 척할 필요 없어.","JPN":"頑張って知らないふりをする必要はないわ。","ENG":"There is no need to act like everything is all right.","TWN":"你沒必要勉強裝作若無其事的樣子。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너도 알다시피 난 악마야. 너흴 공격했던 그 녀석과 똑같은 부류지.","JPN":"アナタも知ってのとおり、アタシは悪魔よ。アナタたちを攻撃したあいつと同じ部類なの。","ENG":"As you know, I am a devil. The same as the one who attacked you.","TWN":"你也知道了，我是魔鬼，和攻擊你們的那傢伙是同類。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"전 멀린 씨가 악마라도 상관없다고 생각해요.","JPN":"私はマーリンさんが悪魔でも構わないです。","ENG":"I don't care if you're a devil, Merlin.","TWN":"就算梅林祭司長是魔鬼，我也不在乎。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 아는 멀린 씨는 좋은 분이니까요.","JPN":"私の知ってるマーリンさんはいい人ですから。","ENG":"Because the Merlin I know is a good person.","TWN":"因為我認識的梅林是個好人。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기의 지도자가 어떻게 정해지는 건지, 알고는 있어?","JPN":"切り株のリーダーがどうやって決められるか、知ってるかしら。","ENG":"Do you know how the leader of the Stump is chosen?","TWN":"你知道木墩的領導者是怎麼選出來的嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"예언 때문이라고 모르가나에게 들었어요.","JPN":"予言で決めるとモルガナに聞きました。","ENG":"I heard from Morgana that it's through the prophecy.","TWN":"莫甘娜說，是因為預言。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"반역자에게 죽은 아발론의 왕이… 다시 태어나 그루터기를 이끌게 된 거라고요.","JPN":"反逆者に殺されたアバロンの王が……生まれ変わって切り株を導くことになったって。","ENG":"The old king of Avalon, slain by the traitor... will be reborn to lead the Stump.","TWN":"被叛徒殺死的阿瓦隆王…將會重生並領導木墩。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"지금은 어때? 내가 아직도 왕의 환생으로 보이니?","JPN":"今はどう？　アタシがまだ王の生まれ変わりに見える？","ENG":"What do you think now? Do you still believe that I am the king reincarnate?","TWN":"現在怎麼樣？我看起來還像是王的轉世嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그건…","JPN":"それは……","ENG":"That's...","TWN":"這…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"난 왕도 아니고, 죽음을 경험한 인간도 아니야.","JPN":"アタシは王でもないし、死を経験した人間でもないわ。","ENG":"I am no king, nor a human who has experienced death.","TWN":"我既不是王，也不是經歷過死亡的人類。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기의 인간들을 이용하기 위해, 내 정체를 속였을 뿐이지.","JPN":"切り株の人間たちを利用するために、アタシの正体を偽ったの。","ENG":"I merely lied about my identity to the villagers of the Stump to use them.","TWN":"我只是為了利用那些殘存的人類，才隱瞞了我的身份。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼, 그루터기를 이끄는 왕 같은 건… 애초에 존재하지 않았다는 건가요?","JPN":"じゃあ、切り株を導く王なんて……最初から存在しなかったってことですか？","ENG":"Then, are you saying that... the king who is to lead the Stump doesn't exist?","TWN":"那麼，帶領殘存者的王…從一開始就不存在嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아니. 그 예언은 틀림없는 진실이야.","JPN":"いいえ。その予言は間違いのない真実よ。","ENG":"The prophecy itself is undoubtedly true.","TWN":"不，那預言無疑是真實的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"단지, 내가 예언의 다음 구절을 아무에게도 가르치지 않았을 뿐이지.","JPN":"ただ、アタシが予言の続きを誰にも教えなかっただけ。","ENG":"It is just that I didn't teach anyone what the next passage of the prophecy is.","TWN":"只是，我沒有告訴任何人預言的下一段。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이 예언에 알려지지 않은 구절이 있었다고요?","JPN":"この予言に続きがあったんですか？","ENG":"There is a passage in the prophecy that people don't know about?","TWN":"這段預言還有未被公開的部分嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":" <color=#ffd34c>반역자에게 죽은 아발론의 옛왕이 훗날 동토에서 다시 태어나 그루터기를 이끌리라.</color>","JPN":" <color=#ffd34c>反逆者に殺されたアバロンの昔の王が近い将来、凍土で生まれ変わり、切り株を導くであろう。</color>","ENG":"<color=#ffd34c>The old king of Avalon, slain by the traitor, will be reborn in the gelid lands and lead the Stump.</color>","TWN":"<color=#ffd34c>遭叛徒殺害的阿瓦隆國王，將來會在凍土重生並帶領木墩。</color>"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":" <color=#ffd34c>뿔을 갖고 태어난 그녀는 자신이 사랑한 고향을 지켜내고, 그루터기의 악마에게 심장을 잃을지니.</color>","JPN":" <color=#ffd34c>ツノを持って生まれた彼女は、自分が愛した故郷を守り抜き、切り株の悪魔によって心臓を失うであろう。</color>","ENG":"<color=#ffd34c>The girl born with a horn will protect her home, and she will lose her heart to the devil of the Stump.</color>","TWN":"<color=#ffd34c>她將帶著角出生，守護她所愛的故鄉，最後被木墩的魔鬼奪走心臟。</color>"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네?","JPN":"えっ？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"뿔이라면 설마…?","JPN":"ツノって、まさか……？","ENG":"A horn? Then...","TWN":"如果說是角，那麼…？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래.","JPN":"そう。","ENG":"Yes.","TWN":"好了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이가 바로, 예언 속 아발론 왕의 현신이야.","JPN":"あの子が、予言の中にあるアバロン王の化身よ。","ENG":"That child is the king of Avalon from the prophecy.","TWN":"那個孩子，就是預言中阿瓦隆王的化身。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"내가 그루터기를 되살리고 지켜왔던 건 전부, 그 아일 다시 만나기 위해서였으니까.","JPN":"アタシが切り株を蘇らせ守ってきたのは、すべてあの子とまた出会うため。","ENG":"The only reason I reestablished the Stump and protected it was to be able to meet her.","TWN":"我復興並守護殘存者的一切，都是為了再次見到她。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…당신이었군요.","JPN":"……あなただったんですね。","ENG":"...So it was you.","TWN":"原來你是那個…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"황금나무를 되살리기 위해 심장을 바쳤다는 요정이…","JPN":"黄金の木を蘇らせるために心臓を捧げたという妖精……","ENG":"The fairy that offered her heart to resurrect the Golden Tree.","TWN":"為了復活黃金樹而獻出心臟的精靈…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하지만, 대체 언제부터 악마가 되었던 거죠?","JPN":"でも、いったいいつから悪魔になったんですか？","ENG":"But when did you become a devil?","TWN":"但是，你到底是什麼時候變成魔鬼的？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"황금나무를 살려내는 일은… 애초에 한 요정이 감당할 수 있는 게 아니었어.","JPN":"黄金の木を蘇らせることは……そもそも一人の妖精の手に負えることではなかったわ。","ENG":"Reviving the Golden Tree was... never something a single fairy can handle.","TWN":"復活黃金樹的工程…從一開始就不是一個精靈能承受的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"심장과 함께 내 영혼까지 바친 뒤에야, 나무의 일부만을 겨우 되살릴 수 있었지.","JPN":"心臓とともに自分の魂まで捧げてやっと、木の一部を蘇らすことができた。","ENG":"After sacrificing my soul along with my heart, I was barely able to revive a portion of the tree.","TWN":"在獻出心臟和靈魂之後，我才勉強復活了樹的一部分。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신의 영혼을 바쳤다고요?","JPN":"あなたの魂を捧げたんですか？","ENG":"You offered your soul?","TWN":"你還獻出了你的靈魂？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼 멀린 씨는 그루터기에 인류가 정착한 그날부터…","JPN":"じゃあ、マーリンさんは切り株に人間が住み着いたその日から……","ENG":"Then since the day humanity settled in the Stump, you were...","TWN":"那麼梅林從殘存者定居在木墩上的那天起…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래. 이미 악마가 된 거야.","JPN":"そう。すでに悪魔になっていたの。","ENG":"Yes, I was already a devil.","TWN":"是的，已經變成魔鬼了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기의 가능성을 빌어 겨우 이성을 유지하고 있긴 하지만…","JPN":"切り株の可能性を借りてなんとか理性を保っているけれど……","ENG":"I have been able to maintain my sanity by borrowing the Stump's possibilities...","TWN":"雖然借助著木墩中的可能性勉強維持理智…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기에서 멀어지거나 그 수명이 다하는 날엔 나도 그 후작 녀석과 똑같은 괴물이 되겠지.","JPN":"切り株から離れたり、その命が尽きる日にはアタシも侯爵と同じ怪物になるでしょうね。","ENG":"But if I leave the Stump or the Stump's life comes to an end, I will become a monster like Marquis.","TWN":"但一旦離開這裡或者壽命終結，我也會變成和那個侯爵一樣的怪物。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하지만 그걸 알면서도…","JPN":"でも、それをわかっているのに……","ENG":"You knew this would happen...","TWN":"但就算如此…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨는 사람들을 위해 낙원문을 만들고, 역사와 지식을 가르쳐 온 거죠?","JPN":"マーリンさんは人々のために楽園の門を作って、歴史と知識を教えてきたんでしょう？","ENG":"Yet, you've built Avalon's Gate and taught the villagers knowledge and history, haven't you?","TWN":"梅林為人們建造了樂園門，傳授了歷史和知識，對嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그루터기의 수명을 희생하면서까지, 사람을 구하는 연명장치도 만들었고요.","JPN":"切り株の寿命を犠牲にしてまで、人々を救う延命装置も作った。","ENG":"You even made the life support device to save them, even at the cost of shortening the Stump's lifespan.","TWN":"甚至犧牲了木墩的壽命，製造了拯救人類的續命裝置。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨는 아직 인간을 사랑하는 요정이네요.","JPN":"マーリンさんはまだ人間を愛しているのですね。","ENG":"You see, Merlin, you are still a fairy who loves humans.","TWN":"梅林祭司長依然是愛著人類的精靈。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아무것도 모르는 주제에 순진하구나.","JPN":"何も知らないくせに、単純ね。","ENG":"For someone who knows nothing, you surely are naive.","TWN":"什麼都不知道，還真是天真啊。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 뭘 모른다는 거죠?","JPN":"なんのことです？","ENG":"Why do I know nothing?","TWN":"我有什麼不知道的嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네 가슴의 낙인은 아주 오래 전, 내가 남긴 거야.","JPN":"アナタの胸の烙印は遠い昔、アタシが残したものよ。","ENG":"The mark on your chest is something I left a long time ago.","TWN":"你胸口的烙印是很久以前我留下的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아주 오래 전, 아발론의 왕을 살해했던 그 형제에게 형벌로 남긴 표식이지.","JPN":"遠い昔、アバロンの王を殺害したあの兄弟に刑罰として残した印よ。","ENG":"It is the mark I branded the brother who murdered the king of Avalon long ago.","TWN":"那是很久以前，作為對殺害阿瓦隆之王的兄弟的懲罰留下的標記。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그가 남긴 핏줄이 영원히 낙인과 함께 고통받을 수 있도록.","JPN":"彼が残した血筋が永遠に烙印とともに苦しむように。","ENG":"So that his bloodline will be forever in suffering with the mark.","TWN":"為了讓他的後代永遠與烙印一起受苦。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"그 낙인을 가진 죄인이 고결한 팔라딘을 꿈꾸다니, 참으로 가증스럽구나.","JPN":"あの烙印を持つ罪人が高潔なパラディンを夢見るなど、なんと傲慢な。","ENG":"How dare a sinner carrying that mark ever dream of becoming a noble paladin. Disgusting.","TWN":"身上有烙印的罪人竟然也敢夢想成為高貴的聖騎士，真是可笑。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L18_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"방금… 봤어요?","JPN":"今の……見ました？","ENG":"Did... you see that?","TWN":"大家…有看到嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"저 낙인은…! 틀림없어요! 반역자의 낙인입니다!","JPN":"あの烙印は……！　間違いないです！　反逆者の烙印ですよ！","ENG":"That mark...! I'm certain of it! It's the brand of the traitor!","TWN":"那個烙印…！沒錯！是叛徒的烙印！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"미안하구나, 아가.","JPN":"本当にごめんね。","ENG":"I'm sorry, my child.","TWN":"媽媽對不起你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"이렇게 된 건…","JPN":"こうなったのは……","ENG":"It's all my fault...","TWN":"都怪媽媽不好…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"전부 내 잘못이야.","JPN":"全部私のせいなの。","ENG":"that we're living like this.","TWN":"害你必須過這種日子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제 낙인을 새긴 게… 당신이라고요?","JPN":"マーリンさんが、この烙印を……？","ENG":"You... gave me this mark?","TWN":"在我身上留下烙印的…是你嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"꼭… 그렇게까지 해야만 했던 건가요?","JPN":"そこまで……する必要があったんですか？","ENG":"Did you... have to go that far?","TWN":"真的…非得做到這種地步嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"인간은 자신의 만족을 위해서라면, 짧은 생을 담보로 어떤 짓도 서슴지 않아.","JPN":"人間は自分の欲望のためなら、その短い命をかけてなんでもするわ。","ENG":"Humans will do anything for their own satisfaction, even if it means putting their short lives at risk.","TWN":"人類為了自身的滿足，不惜以短暫的生命為代價做任何事情。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"종말로부터 살아남기 위해 널 희생시키려 했던 그들처럼 말이야.","JPN":"終末から生き残るため、アナタを犠牲にしようとした彼らのように。","ENG":"Just like how they tried to sacrifice you in order to save themselves from the apocalypse.","TWN":"就像那些為了從末日中生存下來，而試圖犧牲你的人一樣。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"난 그런 인간을 증오해.","JPN":"アタシはそんな人間を憎悪してる。","ENG":"I despise people like that.","TWN":"我憎恨那樣的人類。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그런 너희를 기꺼이 가르치고 역병을 치료했던 건, 어디까지나 이용하기 위해서였어.","JPN":"そんなアナタたちを喜んで教育して疫病を治療したのは、あくまでも利用するためだったの。","ENG":"The only reason I taught and treated you all is to take advantage of you all.","TWN":"我教導你們並治療瘟疫，只是為了利用你們而已。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"무지하고 병든 인간은 쓸모가 없으니까.","JPN":"無知で病気にかかった人間は利用する価値がないから。","ENG":"For the ignorant and the ill are of no use to me.","TWN":"無知又孱弱的人是沒有用的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"낙원문을 완성하려면, 목숨 바쳐 적철을 모으고 내 연구를 도울 존재가 필요했거든.","JPN":"楽園の門を完成するためには、命を捧げて赤鉄を集め、アタシの研究を手伝ってくれる存在が必要だったのよ。","ENG":"To complete Avalon's Gate, I needed people who were willing to risk their lives to gather Violarite to further my research.","TWN":"為了完成樂園門，需要願意冒著生命危險收集赤鐵，並協助我研究的人類。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼 저를 구한 것도…! 그저 이용하기 위해서일 뿐이었나요?!","JPN":"じゃあ、私のことを助けてくれたのも……！　利用するためだったんですか！？","ENG":"Then your saving me was also...! Just to take advantage of me?!","TWN":"那你救我…也只是為了利用我嗎？！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"말했잖니? 넌 쓸모가 있다고.","JPN":"言ったでしょう？　アナタは価値があるって。","ENG":"Did I not say? I have use for you.","TWN":"我不是說過嗎？你是有用的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"낙원문을 완성하는 데 도움만 된다면…","JPN":"楽園の門を完成させるのに役立つなら……","ENG":"Anyone whom I could use to complete Avalon's Gate...","TWN":"只要能幫助我完成樂園門…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"반역자가 인류를 종말시킬 거란 예언 따윈 아무래도 상관없었으니까.","JPN":"反逆者が人類を滅亡させるなんて予言は、どうでも良かったわ。","ENG":"prophecies of a traitor ending humanity was no matter to me.","TWN":"我根本不會在乎什麼叛徒終結世界的預言。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"전… 그 낙인 때문에 가족과 평생을 숨어 살았어요.","JPN":"私は……この烙印のせいで家族とずっと隠れて暮らしていました。","ENG":"My... family and I had to live in hiding all our lives because of this mark.","TWN":"我…因為那個烙印，和家人一輩子都在躲藏。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"낙인이 있다는 이유로 고향에서 모함을 당해 쫓겨났고, 이 그루터기에서도 종말을 불러올 거라며 멸시당했어요.","JPN":"烙印があるのを理由に故郷から陥られ追い出されて、この切り株でも終末を招と軽蔑されたんです。","ENG":"This mark is why I was banished from my home, and even despised for bringing the apocalypse to the Stump by the villagers.","TWN":"因為這個烙印，我在故鄉被誣陷、被驅逐，在這片土地上也被蔑視為會帶來末日的人。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신은 진심으로…","JPN":"あなたは本当に……","ENG":"Did you really...","TWN":"你是真心地…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 그런 대가를 치르길 바란 건가요?","JPN":"私がそんな仕打ちを受けることを望んでいたんですか？","ENG":"want me to suffer all of that?","TWN":"希望我付出那樣的代價嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"날 증오하고 싶다면, 마음대로 증오해.","JPN":"アタシのことを憎みたいなら、どうぞ。","ENG":"If you want to hate me, do as you please.","TWN":"如果你想要憎恨我，隨你的便。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이제 네 도움은 필요 없으니, 여길 떠나도 말리지 않을 거야.","JPN":"もうアナタの協力は必要ないから、ここから出ていっても止めないわ。","ENG":"I do not require your help anymore, so you are free to go if you want.","TWN":"現在不需要你的説明了，你想離開我也不會阻攔。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이 악마가…!!!!!!!!!!!!!!!!!!!!!!!!!!!!","JPN":"この悪魔……！！！！！！！！","ENG":"You devil...!!!!!!!!!!!!","TWN":"你這個魔鬼…！！！！！！！！！！！！！！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그렇게 가까이에서도 맞히지 못하다니.","JPN":"こんなにも近くにいるのに当てられないなんて。","ENG":"You cannot even hit me from this up-close.","TWN":"這麼近都打不中。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"정말 나약하구나.","JPN":"本当に弱いわね。","ENG":"You really are weak.","TWN":"真是弱。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신이 말한 예언대로라면…","JPN":"あなたが言った予言どおりなら……","ENG":"According to the prophecy...","TWN":"按照你說的預言…"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 앞으로 어떻게 되는 거죠?","JPN":"モルガナはこれからどうなるんですか？","ENG":"what will happen to Morgana after?","TWN":"莫甘娜以後會怎麼樣…？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기의 악마인, 내 손에 죽게 되겠지.","JPN":"切り株の悪魔である、私に殺されるでしょうね。","ENG":"She will die in the hands of the Stump's devil, me.","TWN":"作為樹根的魔鬼，她會死在我的手裡。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그렇게 되는 이유는… 당신이 인간을 증오하는 악마이기 때문인가요?","JPN":"そうなる理由は……あなたが人間を憎悪する悪魔だからですか？","ENG":"And the reason being... that you are a devil who hates humans?","TWN":"那是因為…你是憎恨人類的魔鬼嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"황금나무의 예언에 인과 따윈 아무런 의미가 없어.","JPN":"黄金の木の予言に、因果なんてなんの意味もないの。","ENG":"Causality has no meaning in the Golden Tree's prophecy.","TWN":"在黃金樹的預言中，因果毫無意義。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그저 세계의 정해진 결과만을 알려주고 있을 뿐.","JPN":"ただこの世界の決められた結果を教えてくれているだけ。","ENG":"It merely tells us what the determined outcome of the world is.","TWN":"它只是告知這個世界既定的結果而已。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그게… 내가 낙원문을 완성하려는 이유야.","JPN":"それが……アタシが楽園の門を完成させようとする理由よ。","ENG":"That is... why I am trying to complete Avalon's Gate.","TWN":"那就是…我想完成樂園門的原因。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아일 다른 세계선으로 보낼 수만 있다면, 예언을 피할 수 있을 테니까.","JPN":"あの子を他の世界線に送ることができれば、予言を避けられる。","ENG":"If I can send Morgana to another world, the prophecy will be avoided.","TWN":"如果能把她送到另一個世界，就能避開預言。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};